            </button>
          </div>
          <div className="hidden sm:flex items-center gap-2 text-sm text-slate-500 pl-4">
            <Filter size={18} />
            Filtros
          </div>
        </div>

        {/* Card Grid */}
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">

          {filteredResults.length === 0 && (
             <div className="col-span-full py-12 text-center text-slate-400">
                <FileText className="mx-auto h-12 w-12 mb-3 opacity-20" />
                <p>Nenhuma imagem processada ainda.</p>
             </div>
          )}

          {filteredResults.map((result) => (
            <div key={result.id} className="bg-white rounded-xl shadow-sm border border-slate-200 hover:shadow-md transition-shadow flex flex-col overflow-hidden group relative">

              {/* Image Area */}
              <div className="relative h-48 bg-slate-100 overflow-hidden flex items-center justify-center">
                {result.status === 'processing' ? (
                  <div className="flex flex-col items-center gap-2 z-10">
                     <Loader2 className="h-8 w-8 text-primary animate-spin" />
                     <span className="text-xs font-medium text-slate-500">Analisando IA...</span>
                  </div>
                ) : (
                  <img 
                    className={`w-full h-full object-cover transition-transform duration-500 group-hover:scale-105 ${result.status === 'rejected' ? 'grayscale opacity-75' : ''}`}
                    src={result.imageUrl}
                    alt="Documento"
                  />
                )}

                {/* Classification Badge */}
                {result.aiData && (
                  <div className="absolute top-3 left-3">
                    <span className={`inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium border shadow-sm ${
                      result.aiData.classification === 'CANHOTO' 
                        ? 'bg-blue-100 text-blue-800 border-blue-200' 
                        : 'bg-slate-100 text-slate-800 border-slate-200'
                    }`}>
                      {result.aiData.classification}
                    </span>
                  </div>
                )}

                {/* Remove Button */}
                <div className="absolute top-3 right-3 opacity-0 group-hover:opacity-100 transition-opacity">
                  <button onClick={() => removeResult(result.id)} className="bg-white/90 p-1.5 rounded-lg shadow-sm hover:bg-red-50 hover:text-red-600 transition-colors">
                    <Trash2 size={16} />
                  </button>
                </div>

                <div className="absolute bottom-3 right-3 opacity-0 group-hover:opacity-100 transition-opacity">
                   <button onClick={() => window.open(result.imageUrl, '_blank')} className="bg-white/90 p-1.5 rounded-lg shadow-sm hover:bg-primary hover:text-white transition-colors">
                    <Search size={16} />
                  </button>
                </div>
              </div>

              {/* Status Header */}
              {result.status === 'validated' && (
                <div className="bg-green-50 px-4 py-2 border-b border-green-100 flex items-start gap-2">
                   <CheckCircle2 size={14} className="text-green-600 mt-0.5" />
                   <p className="text-xs text-green-800 font-medium">Validado Automaticamente</p>
                </div>
              )}
               {result.status === 'review' && (
                <div className="bg-amber-50 px-4 py-2 border-b border-amber-100 flex items-start gap-2">
                   <AlertTriangle size={14} className="text-amber-500 mt-0.5" />
                   <p className="text-xs text-amber-800 font-medium">Revisão Necessária</p>
                </div>
              )}
              {result.status === 'rejected' && (
                <div className="bg-red-50 px-4 py-2 border-b border-red-100 flex items-start gap-2">
                   <XCircle size={14} className="text-red-500 mt-0.5" />
                   <p className="text-xs text-red-800 font-medium">{result.errorMessage || 'Rejeitado'}</p>
                </div>
              )}

              {/* Content Details */}
              <div className="p-4 flex-1 flex flex-col gap-3">

                {result.status === 'processing' ? (
                   <div className="space-y-2 mt-2">
                     <div className="h-3 bg-slate-100 rounded w-full animate-pulse"></div>
                     <div className="h-3 bg-slate-100 rounded w-2/3 animate-pulse"></div>
                   </div>
                ) : result.aiData ? (
                  <div className="space-y-2">
                    {/* NF Match Check */}
                    <div className="flex items-center gap-2 text-sm">
                      <div className={`w-5 h-5 rounded-full flex items-center justify-center shrink-0 ${result.aiData.isNfMatch ? 'bg-green-100' : 'bg-red-100'}`}>
                        {result.aiData.isNfMatch 
                          ? <Check size={12} className="text-green-600" /> 
                          : <XCircle size={12} className="text-red-600" />
                        }
                      </div>
                      <span className={`truncate ${!result.aiData.isNfMatch ? 'text-red-600' : 'text-slate-700'}`}>
                        NF: {result.aiData.nfNumberFound || 'Não encontrada'}
                      </span>
                    </div>

                    {/* Signature Check */}
                    {result.aiData.classification === 'CANHOTO' && (
                      <div className="flex items-center gap-2 text-sm">
                         <div className={`w-5 h-5 rounded-full flex items-center justify-center shrink-0 ${result.aiData.isSigned ? 'bg-green-100' : 'bg-slate-100'}`}>
                          {result.aiData.isSigned 
                            ? <Check size={12} className="text-green-600" /> 
                            : <HelpCircle size={12} className="text-slate-400" />
                          }
                        </div>
                        <span className="text-slate-700">
                          {result.aiData.isSigned ? 'Assinatura Detectada' : 'Sem Assinatura'}
                        </span>
                      </div>
                    )}
                  </div>
                ) : (
                  <p className="text-sm text-slate-500 italic">
                    {result.status === 'rejected' && !result.errorMessage 
                      ? 'Processamento falhou' 
                      : 'Aguardando processamento...'}
                  </p>
                )}
              </div>
            </div>
          ))}

        </div>
      </div>
    </div>
  );
};

import React, { useState, useRef } from 'react';
import { 
  History, 
  Hash, 
  Wand2, 
  CloudUpload, 
  Filter, 
  CheckCircle2, 
  HelpCircle, 
  AlertTriangle, 
  XCircle, 
  Check, 
  Search,
  FileText,
  Loader2,
  Trash2
} from 'lucide-react';
import { GoogleGenAI, Type } from "@google/genai";
import { FiscalNoteResult } from '../types';

export const FiscalNoteValidator: React.FC = () => {
  const [nfInput, setNfInput] = useState('');
  const [results, setResults] = useState<FiscalNoteResult[]>([]);
  const [isProcessing, setIsProcessing] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Helper to read file as Base64
  const readFileAsBase64 = (file: File): Promise<string> => {
    return new Promise((resolve, reject) => {
      const reader = new FileReader();
      reader.onload = () => resolve(reader.result as string);
      reader.onerror = reject;
      reader.readAsDataURL(file);
    });
  };

  const handleFileUpload = async (event: React.ChangeEvent<HTMLInputElement>) => {
    const fileList = event.target.files;
    if (!fileList || fileList.length === 0) return;

    if (!nfInput) {
      alert("Por favor, insira o número da Nota Fiscal antes de enviar imagens.");
      if (fileInputRef.current) fileInputRef.current.value = '';
      return;
    }

    // Convert FileList to Array immediately to avoid access issues
    const files: File[] = Array.from(fileList);

    // Create initial state entries
    const newResults: FiscalNoteResult[] = files.map(file => ({
      id: Math.random().toString(36).substr(2, 9),
      fileName: file.name,
      imageUrl: URL.createObjectURL(file), // Create local preview URL
      status: 'processing'
    }));

    // Update UI immediately with processing cards
    setResults(prev => [...newResults, ...prev]);
    setIsProcessing(true);

    // Reset input allows selecting the same file again if needed
    if (fileInputRef.current) fileInputRef.current.value = '';

    // Process files in parallel
    await Promise.all(files.map(async (file, index) => {
      const resultId = newResults[index].id;

      try {
        const base64Data = await readFileAsBase64(file);
        // Extract clean base64 string
        const base64Content = base64Data.split(',')[1];

        await analyzeImageWithGemini(resultId, base64Content, file.type, nfInput);
      } catch (error) {
        console.error("Error processing file", file.name, error);
        updateResult(resultId, { status: 'rejected', errorMessage: 'Erro ao ler arquivo' });
      }
    }));

    setIsProcessing(false);
  };

  const updateResult = (id: string, updates: Partial<FiscalNoteResult>) => {
    setResults(prev => prev.map(r => r.id === id ? { ...r, ...updates } : r));
  };

  const analyzeImageWithGemini = async (resultId: string, base64Image: string, mimeType: string, expectedNf: string) => {
    try {
      if (!process.env.API_KEY) {
        throw new Error("Chave de API não configurada");
      }

      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: {
          parts: [
            {
              inlineData: {
                mimeType: mimeType,
                data: base64Image
              }
            },
            {
              text: `Você é um especialista em logística. Analise esta imagem.
              O número de Nota Fiscal (NF) esperado é: "${expectedNf}".

              Regras:
              1. Classifique a imagem como "CANHOTO" (papel de comprovante, nota fiscal, recibo), "MERCADORIA" (caixas, produtos, caminhão) ou "OUTRO".
              2. Se for "CANHOTO", procure pelo número da NF "${expectedNf}" na imagem. Pode estar manuscrito ou impresso.
              3. Se for "CANHOTO", verifique se há uma assinatura (rabisco, nome escrito) no campo de recebedor.

              Retorne o resultado em JSON seguindo exatamente o schema.`
            }
          ]
        },
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.OBJECT,
            properties: {
              classification: { 
                type: Type.STRING, 
                enum: ["CANHOTO", "MERCADORIA", "OUTRO"],
                description: "Classificação do tipo de imagem" 
              },
              nfNumberFound: { 
                type: Type.STRING, 
                description: "O número da NF encontrado na imagem (se houver)",
                nullable: true 
              },
              isNfMatch: { 
                type: Type.BOOLEAN, 
                description: "Verdadeiro se o número encontrado corresponde ao esperado" 
              },
              isSigned: { 
                type: Type.BOOLEAN, 
                description: "Verdadeiro se houver uma assinatura visual visível" 
              },
              confidence: { 
                type: Type.NUMBER, 
                description: "Nível de confiança da análise (0 a 1)" 
              }
            },
            required: ["classification", "isNfMatch", "isSigned", "confidence"]
          }
        }
      });

      let jsonText = response.text;
      if (!jsonText) throw new Error("Sem resposta da IA");

      // Clean Markdown code blocks if present (e.g. ```json ... ```)
      jsonText = jsonText.replace(/^```json\s*/, '').replace(/\s*```$/, '');

      let aiData;
      try {
        aiData = JSON.parse(jsonText);
      } catch (e) {
        console.error("JSON Parse Error", jsonText);
        throw new Error("Erro ao interpretar resposta da IA");
      }

      // Determine final status based on rules
      let finalStatus: FiscalNoteResult['status'] = 'review';

      if (aiData.classification === 'CANHOTO') {
        if (aiData.isNfMatch && aiData.isSigned) {
          finalStatus = 'validated';
        } else if (!aiData.isNfMatch) {
          finalStatus = 'rejected'; // Canhoto but wrong NF
        } else {
          finalStatus = 'review'; // Canhoto, match NF, but maybe not signed or low confidence
        }
      } else if (aiData.classification === 'MERCADORIA') {
        finalStatus = 'review'; // Might be valid proof of condition, but not a receipt
      } else {
        finalStatus = 'rejected';
      }

      updateResult(resultId, {
        status: finalStatus,
        aiData: aiData
      });

    } catch (error: any) {
      console.error("Gemini API Error:", error);
      updateResult(resultId, { 
        status: 'rejected', 
        errorMessage: error.message || 'Falha na análise da IA' 
      });
    }
  };

  const removeResult = (id: string) => {
    setResults(prev => prev.filter(r => r.id !== id));
  };

  // Filter logic
  const [filterType, setFilterType] = useState<'all' | 'validated' | 'review' | 'processing'>('all');

  const filteredResults = results.filter(r => {
    if (filterType === 'all') return true;
    if (filterType === 'processing') return r.status === 'processing';
    if (filterType === 'validated') return r.status === 'validated';
    if (filterType === 'review') return r.status === 'review' || r.status === 'rejected'; // Group rejected with review for this UI
    return true;
  });

  const counts = {
    validated: results.filter(r => r.status === 'validated').length,
    review: results.filter(r => r.status === 'review' || r.status === 'rejected').length,
    processing: results.filter(r => r.status === 'processing').length
  };

  return (
    <div className="max-w-7xl mx-auto space-y-6">
      {/* Page Header */}
      <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4">
        <div>
          <h1 className="text-2xl font-bold text-slate-900">Validador de Canhotos de Entrega</h1>
          <p className="text-slate-500 mt-1">Verificação alimentada por IA para comprovantes de entrega e notas fiscais.</p>
        </div>
        <div className="flex gap-2">
          <button className="flex items-center gap-2 px-4 py-2 bg-white border border-slate-200 rounded-lg text-slate-700 hover:bg-slate-50 transition-colors text-sm font-medium shadow-sm">
            <History size={18} />
            Histórico
          </button>
        </div>
      </div>

      {/* Input Section */}
      <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
        <div className="p-6">
          <div className="grid lg:grid-cols-3 gap-6">
            {/* Form Inputs */}
            <div className="lg:col-span-1 space-y-4">
              <div>
                <label className="block text-sm font-medium text-slate-700 mb-1.5" htmlFor="nf-number">
                  Número da Nota Fiscal (NF-e)
                </label>
                <div className="relative">
                  <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                    <Hash size={18} className="text-slate-400" />
                  </div>
                  <input
                    className="block w-full pl-10 pr-3 py-2.5 border border-slate-300 rounded-lg bg-slate-50 text-slate-900 placeholder-slate-400 focus:outline-none focus:ring-2 focus:ring-primary focus:border-transparent transition-all sm:text-sm"
                    id="nf-number"
                    placeholder="Ex: 450912001"
                    type="text"
                    value={nfInput}
                    onChange={(e) => setNfInput(e.target.value)}
                  />
                </div>
                <p className="mt-1 text-xs text-slate-500">Digite o número da NF para conciliar com o canhoto.</p>
              </div>
              <div className="pt-2">
                <button 
                  onClick={() => fileInputRef.current?.click()}
                  disabled={!nfInput || isProcessing}
                  className={`w-full font-medium py-2.5 px-4 rounded-lg shadow-md transition-all flex items-center justify-center gap-2 ${
                    !nfInput || isProcessing 
                    ? 'bg-slate-300 text-slate-500 cursor-not-allowed' 
                    : 'bg-primary hover:bg-primary-hover text-white hover:shadow-lg'
                  }`}
                >
                  {isProcessing ? <Loader2 className="animate-spin" size={18}/> : <Wand2 size={18} />}
                  {isProcessing ? 'Processando...' : 'Selecionar Imagens & Validar'}
                </button>
              </div>
            </div>

            {/* Dropzone */}
            <div className="lg:col-span-2">
              <input 
                type="file" 
                ref={fileInputRef} 
                onChange={handleFileUpload} 
                className="hidden" 
                multiple 
                accept="image/*"
              />
              <div 
                onClick={() => !isProcessing && fileInputRef.current?.click()}
                className={`border-2 border-dashed border-slate-300 rounded-xl p-8 flex flex-col items-center justify-center text-center transition-colors h-40 group ${
                  !isProcessing ? 'cursor-pointer hover:border-primary hover:bg-primary/5' : 'cursor-default opacity-50'
                }`}
              >
                <div className="bg-primary/10 p-3 rounded-full mb-3 group-hover:scale-110 transition-transform">
                  <CloudUpload className="text-primary h-6 w-6" />
                </div>
                <p className="text-sm text-slate-900 font-medium">Clique para enviar ou arraste e solte</p>
                <p className="text-xs text-slate-500 mt-1">PDF, PNG, JPG (máx. 5MB)</p>
              </div>
            </div>
          </div>
        </div>
      </div>

      {/* Results Section */}
      <div className="space-y-4">
        {/* Filters */}
        <div className="flex items-center justify-between border-b border-slate-200 pb-1 overflow-x-auto">
          <div className="flex gap-6 min-w-max">
            <button 
              onClick={() => setFilterType('all')}
              className={`pb-3 border-b-2 font-medium text-sm whitespace-nowrap transition-colors ${filterType === 'all' ? 'border-primary text-primary' : 'border-transparent text-slate-500 hover:text-slate-700'}`}
            >
              Todos
            </button>
            <button 
              onClick={() => setFilterType('validated')}
              className={`pb-3 border-b-2 font-medium text-sm whitespace-nowrap transition-colors ${filterType === 'validated' ? 'border-primary text-primary' : 'border-transparent text-slate-500 hover:text-slate-700'}`}
            >
              Validados <span className="ml-1 bg-green-100 text-green-700 py-0.5 px-2 rounded-full text-xs">{counts.validated}</span>
            </button>
            <button 
              onClick={() => setFilterType('review')}
              className={`pb-3 border-b-2 font-medium text-sm whitespace-nowrap transition-colors ${filterType === 'review' ? 'border-primary text-primary' : 'border-transparent text-slate-500 hover:text-slate-700'}`}
            >
              Revisão Necessária <span className="ml-1 bg-yellow-100 text-yellow-700 py-0.5 px-2 rounded-full text-xs">{counts.review}</span>
            </button>
            <button 
              onClick={() => setFilterType('processing')}
              className={`pb-3 border-b-2 font-medium text-sm whitespace-nowrap transition-colors ${filterType === 'processing' ? 'border-primary text-primary' : 'border-transparent text-slate-500 hover:text-slate-700'}`}
            >
              Processando <span className="ml-1 bg-slate-100 text-slate-600 py-0.5 px-2 rounded-full text-xs">{counts.processing}</span>
            </button>
          </div>
          <div className="hidden sm:flex items-center gap-2 text-sm text-slate-500 pl-4">
            <Filter size={18} />
            Filtros
          </div>
        </div>

        {/* Card Grid */}
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">

          {filteredResults.length === 0 && (
             <div className="col-span-full py-12 text-center text-slate-400">
                <FileText className="mx-auto h-12 w-12 mb-3 opacity-20" />
                <p>Nenhuma imagem processada ainda.</p>
             </div>
          )}

          {filteredResults.map((result) => (
            <div key={result.id} className="bg-white rounded-xl shadow-sm border border-slate-200 hover:shadow-md transition-shadow flex flex-col overflow-hidden group relative">

              {/* Image Area */}
              <div className="relative h-48 bg-slate-100 overflow-hidden flex items-center justify-center">
                {result.status === 'processing' ? (
                  <div className="flex flex-col items-center gap-2 z-10">
                     <Loader2 className="h-8 w-8 text-primary animate-spin" />
                     <span className="text-xs font-medium text-slate-500">Analisando IA...</span>
                  </div>
                ) : (
                  <img 
                    className={`w-full h-full object-cover transition-transform duration-500 group-hover:scale-105 ${result.status === 'rejected' ? 'grayscale opacity-75' : ''}`}
                    src={result.imageUrl}
                    alt="Documento"
                  />
                )}

                {/* Classification Badge */}
                {result.aiData && (
                  <div className="absolute top-3 left-3">
                    <span className={`inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium border shadow-sm ${
                      result.aiData.classification === 'CANHOTO' 
                        ? 'bg-blue-100 text-blue-800 border-blue-200' 
                        : 'bg-slate-100 text-slate-800 border-slate-200'
                    }`}>
                      {result.aiData.classification}
                    </span>
                  </div>
                )}

                {/* Remove Button */}
                <div className="absolute top-3 right-3 opacity-0 group-hover:opacity-100 transition-opacity">
                  <button onClick={() => removeResult(result.id)} className="bg-white/90 p-1.5 rounded-lg shadow-sm hover:bg-red-50 hover:text-red-600 transition-colors">
                    <Trash2 size={16} />
                  </button>
                </div>

                <div className="absolute bottom-3 right-3 opacity-0 group-hover:opacity-100 transition-opacity">
                   <button onClick={() => window.open(result.imageUrl, '_blank')} className="bg-white/90 p-1.5 rounded-lg shadow-sm hover:bg-primary hover:text-white transition-colors">
                    <Search size={16} />
                  </button>
                </div>
              </div>

              {/* Status Header */}
              {result.status === 'validated' && (
                <div className="bg-green-50 px-4 py-2 border-b border-green-100 flex items-start gap-2">
                   <CheckCircle2 size={14} className="text-green-600 mt-0.5" />
                   <p className="text-xs text-green-800 font-medium">Validado Automaticamente</p>
                </div>
              )}
               {result.status === 'review' && (
                <div className="bg-amber-50 px-4 py-2 border-b border-amber-100 flex items-start gap-2">
                   <AlertTriangle size={14} className="text-amber-500 mt-0.5" />
                   <p className="text-xs text-amber-800 font-medium">Revisão Necessária</p>
                </div>
              )}
              {result.status === 'rejected' && (
                <div className="bg-red-50 px-4 py-2 border-b border-red-100 flex items-start gap-2">
                   <XCircle size={14} className="text-red-500 mt-0.5" />
                   <p className="text-xs text-red-800 font-medium">{result.errorMessage || 'Rejeitado'}</p>
                </div>
              )}

              {/* Content Details */}
              <div className="p-4 flex-1 flex flex-col gap-3">

                {result.status === 'processing' ? (
                   <div className="space-y-2 mt-2">
                     <div className="h-3 bg-slate-100 rounded w-full animate-pulse"></div>
                     <div className="h-3 bg-slate-100 rounded w-2/3 animate-pulse"></div>
                   </div>
                ) : result.aiData ? (
                  <div className="space-y-2">
                    {/* NF Match Check */}
                    <div className="flex items-center gap-2 text-sm">
                      <div className={`w-5 h-5 rounded-full flex items-center justify-center shrink-0 ${result.aiData.isNfMatch ? 'bg-green-100' : 'bg-red-100'}`}>
                        {result.aiData.isNfMatch 
                          ? <Check size={12} className="text-green-600" /> 
                          : <XCircle size={12} className="text-red-600" />
                        }
                      </div>
                      <span className={`truncate ${!result.aiData.isNfMatch ? 'text-red-600' : 'text-slate-700'}`}>
                        NF: {result.aiData.nfNumberFound || 'Não encontrada'}
                      </span>
                    </div>

                    {/* Signature Check */}
                    {result.aiData.classification === 'CANHOTO' && (
                      <div className="flex items-center gap-2 text-sm">
                         <div className={`w-5 h-5 rounded-full flex items-center justify-center shrink-0 ${result.aiData.isSigned ? 'bg-green-100' : 'bg-slate-100'}`}>
                          {result.aiData.isSigned 
                            ? <Check size={12} className="text-green-600" /> 
                            : <HelpCircle size={12} className="text-slate-400" />
                          }
                        </div>
                        <span className="text-slate-700">
                          {result.aiData.isSigned ? 'Assinatura Detectada' : 'Sem Assinatura'}
                        </span>
                      </div>
                    )}
                  </div>
                ) : (
                  <p className="text-sm text-slate-500 italic">
                    {result.status === 'rejected' && !result.errorMessage 
                      ? 'Processamento falhou' 
                      : 'Aguardando processamento...'}
                  </p>
                )}
              </div>
            </div>
          ))}

        </div>
      </div>
    </div>
  );
};

import React, { useState, useRef } from 'react';
import { 
  History, 
  Hash, 
  Wand2, 
  CloudUpload, 
  Filter, 
  CheckCircle2, 
  HelpCircle, 
  AlertTriangle, 
  XCircle, 
  Check, 
  Search,
  FileText,
  Loader2,
  Trash2
} from 'lucide-react';
import { GoogleGenAI, Type } from "@google/genai";
import { FiscalNoteResult } from '../types';

export const FiscalNoteValidator: React.FC = () => {
  const [nfInput, setNfInput] = useState('');
  const [results, setResults] = useState<FiscalNoteResult[]>([]);
  const [isProcessing, setIsProcessing] = useState(false);
  const [isDragging, setIsDragging] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Helper to read file as Base64
  const readFileAsBase64 = (file: File): Promise<string> => {
    return new Promise((resolve, reject) => {
      const reader = new FileReader();
      reader.onload = () => resolve(reader.result as string);
      reader.onerror = reject;
      reader.readAsDataURL(file);
    });
  };

  const processFiles = async (files: File[]) => {
    if (files.length === 0) return;

    if (!nfInput) {
      alert("Por favor, insira o número da Nota Fiscal antes de enviar imagens.");
      if (fileInputRef.current) fileInputRef.current.value = '';
      return;
    }

    // Create initial state entries
    const newResults: FiscalNoteResult[] = files.map(file => ({
      id: Math.random().toString(36).substr(2, 9),
      fileName: file.name,
      imageUrl: URL.createObjectURL(file), // Create local preview URL
      status: 'processing'
    }));

    // Update UI immediately with processing cards
    setResults(prev => [...newResults, ...prev]);
    setIsProcessing(true);

    // Reset input allows selecting the same file again if needed
    if (fileInputRef.current) fileInputRef.current.value = '';

    // Process files in parallel
    await Promise.all(files.map(async (file, index) => {
      const resultId = newResults[index].id;

      try {
        const base64Data = await readFileAsBase64(file);
        // Extract clean base64 string
        const base64Content = base64Data.split(',')[1];

        await analyzeImageWithGemini(resultId, base64Content, file.type, nfInput);
      } catch (error) {
        console.error("Error processing file", file.name, error);
        updateResult(resultId, { status: 'rejected', errorMessage: 'Erro ao ler arquivo' });
      }
    }));

    setIsProcessing(false);
  };

  const handleFileUpload = async (event: React.ChangeEvent<HTMLInputElement>) => {
    const fileList = event.target.files;
    if (!fileList) return;
    await processFiles(Array.from(fileList));
  };

  const handleDragOver = (e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(true);
  };

  const handleDragLeave = (e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(false);
  };

  const handleDrop = async (e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(false);

    if (e.dataTransfer.files && e.dataTransfer.files.length > 0) {
      await processFiles(Array.from(e.dataTransfer.files));
    }
  };

  const updateResult = (id: string, updates: Partial<FiscalNoteResult>) => {
    setResults(prev => prev.map(r => r.id === id ? { ...r, ...updates } : r));
  };

  const analyzeImageWithGemini = async (resultId: string, base64Image: string, mimeType: string, expectedNf: string) => {
    try {
      if (!process.env.API_KEY) {
        throw new Error("Chave de API não configurada");
      }

      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: {
          parts: [
            {
              inlineData: {
                mimeType: mimeType,
                data: base64Image
              }
            },
            {
              text: `Você é um especialista em logística. Analise esta imagem.
              O número de Nota Fiscal (NF) esperado é: "${expectedNf}".

              Regras:
              1. Classifique a imagem como "CANHOTO" (papel de comprovante, nota fiscal, recibo), "MERCADORIA" (caixas, produtos, caminhão) ou "OUTRO".
              2. Se for "CANHOTO", procure pelo número da NF "${expectedNf}" na imagem. Pode estar manuscrito ou impresso.
              3. Se for "CANHOTO", verifique RIGOROSAMENTE se há uma assinatura MANUSCRITA (tinta de caneta, rabisco) no campo de recebedor.
                 IMPORTANTE: Se o campo estiver em branco, vazio ou contiver apenas linhas/textos impressos do próprio formulário, retorne isSigned: FALSE. Só retorne TRUE se houver claramente uma escrita manual.

              Retorne o resultado em JSON seguindo exatamente o schema.`
            }
          ]
        },
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.OBJECT,
            properties: {
              classification: { 
                type: Type.STRING, 
                enum: ["CANHOTO", "MERCADORIA", "OUTRO"],
                description: "Classificação do tipo de imagem" 
              },
              nfNumberFound: { 
                type: Type.STRING, 
                description: "O número da NF encontrado na imagem (se houver)",
                nullable: true 
              },
              isNfMatch: { 
                type: Type.BOOLEAN, 
                description: "Verdadeiro se o número encontrado corresponde ao esperado" 
              },
              isSigned: { 
                type: Type.BOOLEAN, 
                description: "Verdadeiro APENAS se houver uma assinatura manuscrita visível. Falso se estiver em branco." 
              },
              confidence: { 
                type: Type.NUMBER, 
                description: "Nível de confiança da análise (0 a 1)" 
              }
            },
            required: ["classification", "isNfMatch", "isSigned", "confidence"]
          }
        }
      });

      let jsonText = response.text;
      if (!jsonText) throw new Error("Sem resposta da IA");

      // Clean Markdown code blocks if present (e.g. ```json ... ```)
      jsonText = jsonText.replace(/^```json\s*/, '').replace(/\s*```$/, '');

      let aiData;
      try {
        aiData = JSON.parse(jsonText);
      } catch (e) {
        console.error("JSON Parse Error", jsonText);
        throw new Error("Erro ao interpretar resposta da IA");
      }

      // Determine final status based on rules
      let finalStatus: FiscalNoteResult['status'] = 'review';

      if (aiData.classification === 'CANHOTO') {
        if (aiData.isNfMatch && aiData.isSigned) {
          finalStatus = 'validated';
        } else if (!aiData.isNfMatch) {
          finalStatus = 'rejected'; // Canhoto but wrong NF
        } else {
          finalStatus = 'review'; // Canhoto, match NF, but maybe not signed or low confidence
        }
      } else if (aiData.classification === 'MERCADORIA') {
        finalStatus = 'review'; // Might be valid proof of condition, but not a receipt
      } else {
        finalStatus = 'rejected';
      }

      updateResult(resultId, {
        status: finalStatus,
        aiData: aiData
      });

    } catch (error: any) {
      console.error("Gemini API Error:", error);
      updateResult(resultId, { 
        status: 'rejected', 
        errorMessage: error.message || 'Falha na análise da IA' 
      });
    }
  };

  const removeResult = (id: string) => {
    setResults(prev => prev.filter(r => r.id !== id));
  };

  // Filter logic
  const [filterType, setFilterType] = useState<'all' | 'validated' | 'review' | 'processing'>('all');

  const filteredResults = results.filter(r => {
    if (filterType === 'all') return true;
    if (filterType === 'processing') return r.status === 'processing';
    if (filterType === 'validated') return r.status === 'validated';
    if (filterType === 'review') return r.status === 'review' || r.status === 'rejected'; // Group rejected with review for this UI
    return true;
  });

  const counts = {
    validated: results.filter(r => r.status === 'validated').length,
    review: results.filter(r => r.status === 'review' || r.status === 'rejected').length,
    processing: results.filter(r => r.status === 'processing').length
  };

  return (
    <div className="max-w-7xl mx-auto space-y-6">
      {/* Page Header */}
      <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4">
        <div>
          <h1 className="text-2xl font-bold text-slate-900">Validador de Canhotos de Entrega</h1>
          <p className="text-slate-500 mt-1">Verificação alimentada por IA para comprovantes de entrega e notas fiscais.</p>
        </div>
        <div className="flex gap-2">
          <button className="flex items-center gap-2 px-4 py-2 bg-white border border-slate-200 rounded-lg text-slate-700 hover:bg-slate-50 transition-colors text-sm font-medium shadow-sm">
            <History size={18} />
            Histórico
          </button>
        </div>
      </div>

      {/* Input Section */}
      <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
        <div className="p-6">
          <div className="grid lg:grid-cols-3 gap-6">
            {/* Form Inputs */}
            <div className="lg:col-span-1 space-y-4">
              <div>
                <label className="block text-sm font-medium text-slate-700 mb-1.5" htmlFor="nf-number">
                  Número da Nota Fiscal (NF-e)
                </label>
                <div className="relative">
                  <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                    <Hash size={18} className="text-slate-400" />
                  </div>
                  <input
                    className="block w-full pl-10 pr-3 py-2.5 border border-slate-300 rounded-lg bg-slate-50 text-slate-900 placeholder-slate-400 focus:outline-none focus:ring-2 focus:ring-primary focus:border-transparent transition-all sm:text-sm"
                    id="nf-number"
                    placeholder="Ex: 450912001"
                    type="text"
                    value={nfInput}
                    onChange={(e) => setNfInput(e.target.value)}
                  />
                </div>
                <p className="mt-1 text-xs text-slate-500">Digite o número da NF para conciliar com o canhoto.</p>
              </div>
              <div className="pt-2">
                <button 
                  onClick={() => fileInputRef.current?.click()}
                  disabled={!nfInput || isProcessing}
                  className={`w-full font-medium py-2.5 px-4 rounded-lg shadow-md transition-all flex items-center justify-center gap-2 ${
                    !nfInput || isProcessing 
                    ? 'bg-slate-300 text-slate-500 cursor-not-allowed' 
                    : 'bg-primary hover:bg-primary-hover text-white hover:shadow-lg'
                  }`}
                >
                  {isProcessing ? <Loader2 className="animate-spin" size={18}/> : <Wand2 size={18} />}
                  {isProcessing ? 'Processando...' : 'Selecionar Imagens & Validar'}
                </button>
              </div>
            </div>

            {/* Dropzone */}
            <div className="lg:col-span-2">
              <input 
                type="file" 
                ref={fileInputRef} 
                onChange={handleFileUpload} 
                className="hidden" 
                multiple 
                accept="image/*"
              />
              <div 
                onDragOver={handleDragOver}
                onDragLeave={handleDragLeave}
                onDrop={handleDrop}
                onClick={() => !isProcessing && fileInputRef.current?.click()}
                className={`border-2 border-dashed rounded-xl p-8 flex flex-col items-center justify-center text-center transition-all h-40 group ${
                  isDragging 
                    ? 'border-primary bg-primary/10 scale-[1.02]' 
                    : !isProcessing 
                      ? 'border-slate-300 hover:border-primary hover:bg-primary/5 cursor-pointer' 
                      : 'border-slate-200 cursor-default opacity-50'
                }`}
              >
                <div className={`p-3 rounded-full mb-3 transition-transform ${isDragging ? 'bg-primary/20 scale-110' : 'bg-primary/10 group-hover:scale-110'}`}>
                  <CloudUpload className="text-primary h-6 w-6" />
                </div>
                <p className="text-sm text-slate-900 font-medium">Clique para enviar ou arraste e solte</p>
                <p className="text-xs text-slate-500 mt-1">PDF, PNG, JPG (máx. 5MB)</p>
              </div>
            </div>
          </div>
        </div>
      </div>

      {/* Results Section */}
      <div className="space-y-4">
        {/* Filters */}
        <div className="flex items-center justify-between border-b border-slate-200 pb-1 overflow-x-auto">
          <div className="flex gap-6 min-w-max">
            <button 
              onClick={() => setFilterType('all')}
              className={`pb-3 border-b-2 font-medium text-sm whitespace-nowrap transition-colors ${filterType === 'all' ? 'border-primary text-primary' : 'border-transparent text-slate-500 hover:text-slate-700'}`}
            >
              Todos
            </button>
            <button 
              onClick={() => setFilterType('validated')}
              className={`pb-3 border-b-2 font-medium text-sm whitespace-nowrap transition-colors ${filterType === 'validated' ? 'border-primary text-primary' : 'border-transparent text-slate-500 hover:text-slate-700'}`}
            >
              Validados <span className="ml-1 bg-green-100 text-green-700 py-0.5 px-2 rounded-full text-xs">{counts.validated}</span>
            </button>
            <button 
              onClick={() => setFilterType('review')}
              className={`pb-3 border-b-2 font-medium text-sm whitespace-nowrap transition-colors ${filterType === 'review' ? 'border-primary text-primary' : 'border-transparent text-slate-500 hover:text-slate-700'}`}
            >
              Revisão Necessária <span className="ml-1 bg-yellow-100 text-yellow-700 py-0.5 px-2 rounded-full text-xs">{counts.review}</span>
            </button>
            <button 
              onClick={() => setFilterType('processing')}
              className={`pb-3 border-b-2 font-medium text-sm whitespace-nowrap transition-colors ${filterType === 'processing' ? 'border-primary text-primary' : 'border-transparent text-slate-500 hover:text-slate-700'}`}
            >
              Processando <span className="ml-1 bg-slate-100 text-slate-600 py-0.5 px-2 rounded-full text-xs">{counts.processing}</span>
            </button>
          </div>
          <div className="hidden sm:flex items-center gap-2 text-sm text-slate-500 pl-4">
            <Filter size={18} />
            Filtros
          </div>
        </div>

        {/* Card Grid */}
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">

          {filteredResults.length === 0 && (
             <div className="col-span-full py-12 text-center text-slate-400">
                <FileText className="mx-auto h-12 w-12 mb-3 opacity-20" />
                <p>Nenhuma imagem processada ainda.</p>
             </div>
          )}

          {filteredResults.map((result) => (
            <div key={result.id} className="bg-white rounded-xl shadow-sm border border-slate-200 hover:shadow-md transition-shadow flex flex-col overflow-hidden group relative">

              {/* Image Area */}
              <div className="relative h-48 bg-slate-100 overflow-hidden flex items-center justify-center">
                {result.status === 'processing' ? (
                  <div className="flex flex-col items-center gap-2 z-10">
                     <Loader2 className="h-8 w-8 text-primary animate-spin" />
                     <span className="text-xs font-medium text-slate-500">Analisando IA...</span>
                  </div>
                ) : (
                  <img 
                    className={`w-full h-full object-cover transition-transform duration-500 group-hover:scale-105 ${result.status === 'rejected' ? 'grayscale opacity-75' : ''}`}
                    src={result.imageUrl}
                    alt="Documento"
                  />
                )}

                {/* Classification Badge */}
                {result.aiData && (
                  <div className="absolute top-3 left-3">
                    <span className={`inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium border shadow-sm ${
                      result.aiData.classification === 'CANHOTO' 
                        ? 'bg-blue-100 text-blue-800 border-blue-200' 
                        : 'bg-slate-100 text-slate-800 border-slate-200'
                    }`}>
                      {result.aiData.classification}
                    </span>
                  </div>
                )}

                {/* Remove Button */}
                <div className="absolute top-3 right-3 opacity-0 group-hover:opacity-100 transition-opacity">
                  <button onClick={() => removeResult(result.id)} className="bg-white/90 p-1.5 rounded-lg shadow-sm hover:bg-red-50 hover:text-red-600 transition-colors">
                    <Trash2 size={16} />
                  </button>
                </div>

                <div className="absolute bottom-3 right-3 opacity-0 group-hover:opacity-100 transition-opacity">
                   <button onClick={() => window.open(result.imageUrl, '_blank')} className="bg-white/90 p-1.5 rounded-lg shadow-sm hover:bg-primary hover:text-white transition-colors">
                    <Search size={16} />
                  </button>
                </div>
              </div>

              {/* Status Header */}
              {result.status === 'validated' && (
                <div className="bg-green-50 px-4 py-2 border-b border-green-100 flex items-start gap-2">
                   <CheckCircle2 size={14} className="text-green-600 mt-0.5" />
                   <p className="text-xs text-green-800 font-medium">Validado Automaticamente</p>
                </div>
              )}
               {result.status === 'review' && (
                <div className="bg-amber-50 px-4 py-2 border-b border-amber-100 flex items-start gap-2">
                   <AlertTriangle size={14} className="text-amber-500 mt-0.5" />
                   <p className="text-xs text-amber-800 font-medium">Revisão Necessária</p>
                </div>
              )}
              {result.status === 'rejected' && (
                <div className="bg-red-50 px-4 py-2 border-b border-red-100 flex items-start gap-2">
                   <XCircle size={14} className="text-red-500 mt-0.5" />
                   <p className="text-xs text-red-800 font-medium">{result.errorMessage || 'Rejeitado'}</p>
                </div>
              )}

              {/* Content Details */}
              <div className="p-4 flex-1 flex flex-col gap-3">

                {result.status === 'processing' ? (
                   <div className="space-y-2 mt-2">
                     <div className="h-3 bg-slate-100 rounded w-full animate-pulse"></div>
                     <div className="h-3 bg-slate-100 rounded w-2/3 animate-pulse"></div>
                   </div>
                ) : result.aiData ? (
                  <div className="space-y-2">
                    {/* NF Match Check */}
                    <div className="flex items-center gap-2 text-sm">
                      <div className={`w-5 h-5 rounded-full flex items-center justify-center shrink-0 ${result.aiData.isNfMatch ? 'bg-green-100' : 'bg-red-100'}`}>
                        {result.aiData.isNfMatch 
                          ? <Check size={12} className="text-green-600" /> 
                          : <XCircle size={12} className="text-red-600" />
                        }
                      </div>
                      <span className={`truncate ${!result.aiData.isNfMatch ? 'text-red-600' : 'text-slate-700'}`}>
                        NF: {result.aiData.nfNumberFound || 'Não encontrada'}
                      </span>
                    </div>

                    {/* Signature Check */}
                    {result.aiData.classification === 'CANHOTO' && (
                      <div className="flex items-center gap-2 text-sm">
                         <div className={`w-5 h-5 rounded-full flex items-center justify-center shrink-0 ${result.aiData.isSigned ? 'bg-green-100' : 'bg-slate-100'}`}>
                          {result.aiData.isSigned 
                            ? <Check size={12} className="text-green-600" /> 
                            : <HelpCircle size={12} className="text-slate-400" />
                          }
                        </div>
                        <span className="text-slate-700">
                          {result.aiData.isSigned ? 'Assinatura Detectada' : 'Sem Assinatura'}
                        </span>
                      </div>
                    )}
                  </div>
                ) : (
                  <p className="text-sm text-slate-500 italic">
                    {result.status === 'rejected' && !result.errorMessage 
                      ? 'Processamento falhou' 
                      : 'Aguardando processamento...'}
                  </p>
                )}
              </div>
            </div>
          ))}

        </div>
      </div>
    </div>
  );
};

import React, { useState, useRef, useEffect } from 'react';
import { 
  Image as ImageIcon, 
  ZoomIn, 
  Upload, 
  Edit3, 
  AlertCircle, 
  TriangleAlert, 
  ArrowRight, 
  Flag, 
  Check,
  Loader2,
  RefreshCw,
  Save
} from 'lucide-react';
import { ASSETS, Vehicle, VerificationData } from '../types';
import { GoogleGenAI, Type } from "@google/genai";

interface ValidationCardProps {
  vehicles: Vehicle[];
  onValidationComplete: (data: VerificationData) => void;
}

export const ValidationCard: React.FC<ValidationCardProps> = ({ vehicles, onValidationComplete }) => {
  // Application State
  const [imageSrc, setImageSrc] = useState<string>(ASSETS.dashboard);
  const [manualMileage, setManualMileage] = useState<string>('12500');
  const [aiMileage, setAiMileage] = useState<number | null>(12580);
  const [confidence, setConfidence] = useState<number>(0.98);
  const [isAnalyzing, setIsAnalyzing] = useState<boolean>(false);
  const [status, setStatus] = useState<'idle' | 'success' | 'divergence' | 'error'>('divergence');
  const [errorMessage, setErrorMessage] = useState<string>('');
  const [selectedVehicleId, setSelectedVehicleId] = useState<string>(vehicles.length > 0 ? vehicles[0].id : '');
  const [isSaved, setIsSaved] = useState(false);

  const fileInputRef = useRef<HTMLInputElement>(null);

  // Update selected vehicle if the list changes and current selection is invalid
  useEffect(() => {
    if (vehicles.length > 0 && !vehicles.find(v => v.id === selectedVehicleId)) {
        setSelectedVehicleId(vehicles[0].id);
    }
  }, [vehicles, selectedVehicleId]);

  // Derived state
  const numericManual = parseInt(manualMileage.replace(/\D/g, '') || '0', 10);
  const hasDivergence = aiMileage !== null && numericManual !== aiMileage;

  // Effect to update status based on values
  useEffect(() => {
    // Only update status if we haven't saved yet (lock state after save)
    if (!isSaved) {
      if (aiMileage !== null && hasDivergence) {
        setStatus('divergence');
      } else if (aiMileage !== null && !hasDivergence) {
        setStatus('success');
      }
    }
  }, [manualMileage, aiMileage, hasDivergence, isSaved]);

  // Helper: Convert File to Base64
  const fileToBase64 = (file: File): Promise<string> => {
    return new Promise((resolve, reject) => {
      const reader = new FileReader();
      reader.readAsDataURL(file);
      reader.onload = () => resolve(reader.result as string);
      reader.onerror = error => reject(error);
    });
  };

  // Handler: File Selection
  const handleFileChange = async (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    try {
      setIsAnalyzing(true);
      setErrorMessage('');
      setIsSaved(false); // Reset saved state for new image
      const base64Data = await fileToBase64(file);
      setImageSrc(base64Data);

      // Extract clean base64 string (remove data:image/jpeg;base64, prefix)
      const base64Content = base64Data.split(',')[1];
      await analyzeImageWithGemini(base64Content, file.type);

    } catch (error) {
      console.error("Error processing file:", error);
      setErrorMessage("Erro ao processar a imagem.");
      setIsAnalyzing(false);
    }
  };

  // Function: Call Gemini API
  const analyzeImageWithGemini = async (base64Image: string, mimeType: string) => {
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: {
          parts: [
            {
              inlineData: {
                mimeType: mimeType,
                data: base64Image
              }
            },
            {
              text: "Analyze this dashboard image. Identify the odometer reading (total distance traveled). Ignore trip meters (usually smaller numbers or with decimals). Return the value as an integer."
            }
          ]
        },
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.OBJECT,
            properties: {
              mileage: { type: Type.INTEGER, description: "The odometer reading value" },
              confidence: { type: Type.NUMBER, description: "Confidence score between 0 and 1" }
            },
            required: ["mileage", "confidence"]
          }
        }
      });

      const jsonText = response.text;
      if (jsonText) {
        const result = JSON.parse(jsonText);
        setAiMileage(result.mileage);
        setConfidence(result.confidence);
        // Auto-fill manual mileage for UX convenience if it was empty/zero
        if (numericManual === 0) {
            setManualMileage(String(result.mileage));
        }
      } else {
        throw new Error("No data returned");
      }
    } catch (error) {
      console.error("Gemini API Error:", error);
      setErrorMessage("Não foi possível ler o odômetro. Tente uma foto mais clara.");
      setAiMileage(null);
    } finally {
      setIsAnalyzing(false);
    }
  };

  const triggerFileUpload = () => {
    fileInputRef.current?.click();
  };

  const completeValidation = (finalMileage: number) => {
    const data: VerificationData = {
      id: Math.random().toString(36).substr(2, 9),
      imageUrl: imageSrc,
      imageDate: new Date().toISOString(),
      imageSize: 'N/A',
      vehicleId: selectedVehicleId,
      manualMileage: finalMileage,
      aiMileage: aiMileage || 0,
      confidence: confidence,
      status: 'success'
    };

    onValidationComplete(data);
    setIsSaved(true);
    setStatus('success');
  };

  const handleAcceptAiValue = () => {
    if (aiMileage !== null) {
      setManualMileage(String(aiMileage));
      completeValidation(aiMileage);
    }
  };

  const handleManualConfirm = () => {
    completeValidation(numericManual);
  };

  return (
    <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
      <input 
        type="file" 
        ref={fileInputRef} 
        onChange={handleFileChange} 
        className="hidden" 
        accept="image/*"
      />

      <div className="grid grid-cols-1 lg:grid-cols-2">
        {/* Left: Image Upload/Preview */}
        <div className="p-6 lg:p-8 bg-slate-50 border-b lg:border-b-0 lg:border-r border-slate-200 flex flex-col">
          <h3 className="text-sm font-semibold text-slate-900 mb-4 flex items-center gap-2">
            <ImageIcon size={18} className="text-primary" />
            Evidência Fotográfica
          </h3>

          <div className="flex-1 min-h-[300px] relative rounded-lg overflow-hidden group border-2 border-dashed border-slate-300 hover:border-primary/50 transition-colors bg-white">
            {isAnalyzing ? (
              <div className="absolute inset-0 flex flex-col items-center justify-center bg-slate-50 z-20">
                <Loader2 className="w-10 h-10 text-primary animate-spin mb-3" />
                <p className="text-sm text-slate-500 font-medium">Analisando imagem com IA...</p>
              </div>
            ) : (
              <img 
                src={imageSrc}
                alt="Dashboard Speedometer" 
                className="w-full h-full object-cover"
              />
            )}

            {/* Hover Actions Overlay */}
            <div className={`absolute inset-0 bg-black/40 transition-opacity flex items-center justify-center gap-3 backdrop-blur-[1px] ${isAnalyzing || isSaved ? 'hidden' : 'opacity-0 group-hover:opacity-100'}`}>
              <button 
                onClick={() => window.open(imageSrc, '_blank')}
                className="bg-white/90 hover:bg-white text-slate-800 px-4 py-2 rounded-lg text-sm font-medium shadow-lg flex items-center gap-2 transition-transform hover:scale-105"
              >
                <ZoomIn size={16} />
                Expandir
              </button>
              <button 
                onClick={triggerFileUpload}
                className="bg-primary hover:bg-primary-hover text-white px-4 py-2 rounded-lg text-sm font-medium shadow-lg flex items-center gap-2 transition-transform hover:scale-105"
              >
                <Upload size={16} />
                Nova Foto
              </button>
            </div>

            {/* AI Focus Box (Simulated visualization of detection) */}
            {!isAnalyzing && aiMileage !== null && (
               <div className="absolute top-[45%] left-[38%] w-32 h-12 border-2 border-primary shadow-[0_0_15px_rgba(19,127,236,0.5)] rounded bg-primary/10 pointer-events-none animate-pulse">
                  <div className="absolute -top-6 left-0 bg-primary text-white text-[10px] font-bold px-1.5 py-0.5 rounded-t uppercase">
                     Confidence: {(confidence * 100).toFixed(0)}%
                  </div>
               </div>
            )}
          </div>

          <div className="mt-4 flex items-center justify-between text-xs text-slate-500 font-mono">
             {errorMessage ? (
               <span className="text-red-500 flex items-center gap-1">
                 <AlertCircle size={14} /> {errorMessage}
               </span>
             ) : (
               <span>Imagem processada</span>
             )}
            {!isSaved && (
              <button onClick={triggerFileUpload} className="text-primary hover:underline">
                Alterar imagem
              </button>
            )}
          </div>
        </div>

        {/* Right: Manual Input & Actions */}
        <div className="p-6 lg:p-8 flex flex-col h-full">
          <h3 className="text-sm font-semibold text-slate-900 mb-6 flex items-center gap-2">
            <Edit3 size={18} className="text-primary" />
            Dados da Leitura
          </h3>

          <form className="space-y-6 flex-1" onSubmit={(e) => e.preventDefault()}>
            <div>
              <label htmlFor="vehicle" className="block text-sm font-medium text-slate-700 mb-1.5">
                Veículo
              </label>
              <div className="relative">
                <select
                  id="vehicle"
                  name="vehicle"
                  disabled={isSaved}
                  className="block w-full rounded-lg border-slate-300 bg-white text-slate-900 shadow-sm focus:border-primary focus:ring-primary sm:text-sm py-2.5 pl-3 pr-10 border disabled:bg-slate-100 disabled:text-slate-500"
                  value={selectedVehicleId}
                  onChange={(e) => setSelectedVehicleId(e.target.value)}
                >
                  {vehicles.length === 0 && <option value="">Nenhum veículo cadastrado</option>}
                  {vehicles.map(v => (
                    <option key={v.id} value={v.id}>{v.name} - {v.plate}</option>
                  ))}
                </select>
              </div>
              {vehicles.length === 0 && (
                <p className="mt-2 text-xs text-red-500">
                  Cadastre veículos no menu "Frota" para prosseguir.
                </p>
              )}
            </div>

            <div>
              <label htmlFor="mileage" className="block text-sm font-medium text-slate-700 mb-1.5">
                Quilometragem Informada (Manual)
              </label>
              <div className="relative rounded-lg shadow-sm">
                <input
                  type="text" 
                  pattern="[0-9]*"
                  name="mileage"
                  id="mileage"
                  disabled={isSaved}
                  className={`block w-full rounded-lg border sm:text-sm py-2.5 pr-12 focus:outline-none focus:ring-1 transition-all disabled:bg-slate-100 ${
                    status === 'divergence' && !isSaved
                      ? 'border-red-300 text-red-900 placeholder-red-300 focus:border-red-500 focus:ring-red-500' 
                      : status === 'success' || isSaved
                        ? 'border-green-300 text-green-900 focus:border-green-500 focus:ring-green-500'
                        : 'border-slate-300 focus:border-primary focus:ring-primary'
                  }`}
                  value={manualMileage}
                  onChange={(e) => setManualMileage(e.target.value)}
                />
                <div className="absolute inset-y-0 right-0 flex items-center pr-3 pointer-events-none">
                  <span className={`${status === 'divergence' && !isSaved ? 'text-red-500' : 'text-slate-500'} sm:text-sm font-medium`}>km</span>
                </div>
                {!isSaved && status === 'divergence' && (
                  <div className="absolute inset-y-0 right-10 flex items-center pointer-events-none">
                    <AlertCircle className="h-5 w-5 text-red-500" aria-hidden="true" />
                  </div>
                )}
                {(status === 'success' || isSaved) && (
                  <div className="absolute inset-y-0 right-10 flex items-center pointer-events-none">
                    <Check className="h-5 w-5 text-green-500" aria-hidden="true" />
                  </div>
                )}
              </div>
              {!isSaved && status === 'divergence' && (
                <p className="mt-2 text-sm text-red-600 animate-in slide-in-from-top-1">
                  Valor diverge da leitura automática.
                </p>
              )}
               {(status === 'success' || isSaved) && (
                <p className="mt-2 text-sm text-green-600 animate-in slide-in-from-top-1">
                  Leitura validada.
                </p>
              )}
            </div>

            <div className="pt-4 border-t border-slate-100 mt-auto">
              {isSaved ? (
                 <button
                 type="button"
                 onClick={() => { setIsSaved(false); setManualMileage(''); setAiMileage(null); setImageSrc(ASSETS.dashboard); }}
                 className="w-full flex justify-center py-2.5 px-4 border border-slate-300 rounded-lg shadow-sm text-sm font-medium text-slate-700 bg-white hover:bg-slate-50 transition-colors"
               >
                 <RefreshCw className="w-5 h-5 mr-2 text-slate-500" />
                 Iniciar Nova Verificação
               </button>
              ) : isAnalyzing ? (
                 <button
                 type="button"
                 disabled
                 className="w-full flex justify-center py-2.5 px-4 border border-transparent rounded-lg shadow-sm text-sm font-medium text-slate-400 bg-slate-100 cursor-not-allowed"
               >
                 <Loader2 className="w-5 h-5 animate-spin mr-2" />
                 Processando...
               </button>
              ) : (
                <button
                  type="button"
                  onClick={() => analyzeImageWithGemini(imageSrc.split(',')[1], 'image/jpeg')}
                  className="w-full flex justify-center items-center py-2.5 px-4 border border-transparent rounded-lg shadow-sm text-sm font-medium text-white bg-primary hover:bg-primary-hover focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-primary transition-colors"
                >
                  <RefreshCw size={18} className="mr-2" />
                  Reprocessar Validação
                </button>
              )}
            </div>
          </form>
        </div>
      </div>

      {/* Validation Result Section */}
      {!isSaved && status === 'divergence' && aiMileage !== null && (
        <div className="border-t border-slate-200 bg-slate-50 p-6 lg:p-8 animate-in slide-in-from-bottom-2 fade-in duration-300">
          <div className="rounded-lg border border-red-200 bg-red-50 p-4">
            <div className="flex">
              <div className="flex-shrink-0">
                <TriangleAlert className="h-6 w-6 text-red-500" aria-hidden="true" />
              </div>
              <div className="ml-3 w-full">
                <h3 className="text-lg font-medium text-red-800">Divergência Detectada</h3>

                <div className="mt-4 flex flex-col sm:flex-row gap-4">
                  {/* Manual Value Chip */}
                  <div className="flex-1 bg-white rounded-lg p-3 shadow-sm border border-red-100 flex flex-col items-center justify-center">
                    <span className="text-xs text-slate-500 uppercase tracking-wider font-semibold">Valor Digitado</span>
                    <span className="text-xl font-bold text-slate-700 font-mono mt-1">
                      {numericManual.toLocaleString('pt-BR')} km
                    </span>
                  </div>

                  <div className="flex items-center justify-center text-red-300">
                    <ArrowRight size={24} />
                  </div>

                  {/* AI Value Chip */}
                  <div className="flex-1 bg-white rounded-lg p-3 shadow-sm border border-primary/20 flex flex-col items-center justify-center relative overflow-hidden">
                    <div className="absolute top-0 right-0 bg-primary text-white text-[10px] font-bold px-1.5 py-0.5 rounded-bl">
                      IA
                    </div>
                    <span className="text-xs text-primary uppercase tracking-wider font-semibold">Extraído pela IA</span>
                    <span className="text-xl font-bold text-primary font-mono mt-1">
                      {aiMileage.toLocaleString('pt-BR')} km
                    </span>
                  </div>
                </div>

                <div className="mt-6 flex gap-3 flex-wrap">
                  <button
                    type="button"
                    className="inline-flex items-center px-4 py-2 border border-transparent text-sm font-medium rounded-lg shadow-sm text-white bg-red-600 hover:bg-red-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-red-500 transition-colors"
                  >
                    <Flag size={16} className="mr-2" />
                    Marcar para Revisão
                  </button>
                  <button
                    type="button"
                    className="inline-flex items-center px-4 py-2 border border-slate-300 shadow-sm text-sm font-medium rounded-lg text-slate-700 bg-white hover:bg-slate-50 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-primary transition-colors"
                    onClick={handleAcceptAiValue}
                  >
                    <Check size={16} className="mr-2 text-green-600" />
                    Aceitar Valor da IA
                  </button>
                </div>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* Success/Saved State */}
      {status === 'success' && (
         <div className="border-t border-slate-200 bg-green-50 p-6 lg:p-8 animate-in slide-in-from-bottom-2 fade-in duration-300">
            <div className="flex items-center justify-between">
              <div className="flex items-center gap-4">
                <div className="h-12 w-12 rounded-full bg-green-100 flex items-center justify-center flex-shrink-0">
                  <Check className="h-6 w-6 text-green-600" />
                </div>
                <div>
                  <h3 className="text-lg font-bold text-green-900">
                    {isSaved ? "Validação Salva" : "Validação Pronta"}
                  </h3>
                  <p className="text-green-700">
                    {isSaved ? "O registro foi adicionado ao histórico com sucesso." : "Os valores conferem. Deseja registrar essa leitura?"}
                  </p>
                </div>
              </div>

              {!isSaved && (
                <button
                  onClick={handleManualConfirm}
                  className="inline-flex items-center px-4 py-2 border border-transparent text-sm font-medium rounded-lg shadow-sm text-white bg-green-600 hover:bg-green-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-green-500 transition-colors"
                >
                  <Save size={16} className="mr-2" />
                  Registrar Leitura
                </button>
              )}
            </div>
         </div>
      )}
    </div>
  );
};

import React, { useState } from 'react';
import { Sidebar } from './components/Sidebar';
import { Header } from './components/Header';
import { ValidationCard } from './components/ValidationCard';
import { FleetManager } from './components/FleetManager';
import { FiscalNoteValidator } from './components/FiscalNoteValidator';
import { CheckCircle2, FileText } from 'lucide-react';
import { MOCK_VEHICLES, Vehicle, VerificationData } from './types';

export default function App() {
  const [currentView, setCurrentView] = useState('validation');
  const [vehicles, setVehicles] = useState<Vehicle[]>(MOCK_VEHICLES);
  const [validationHistory, setValidationHistory] = useState<VerificationData[]>([]);

  // --- CRUD Handlers for Vehicles ---
  const handleAddVehicle = (newVehicleData: Omit<Vehicle, 'id'>) => {
    const newVehicle: Vehicle = {
      ...newVehicleData,
      id: Math.random().toString(36).substr(2, 9) // Simple ID generation
    };
    setVehicles([...vehicles, newVehicle]);
  };

  const handleUpdateVehicle = (updatedVehicle: Vehicle) => {
    setVehicles(vehicles.map(v => v.id === updatedVehicle.id ? updatedVehicle : v));
  };

  const handleDeleteVehicle = (id: string) => {
    setVehicles(vehicles.filter(v => v.id !== id));
  };

  // --- Validation Handler ---
  const handleValidationComplete = (data: VerificationData) => {
    setValidationHistory(prev => [data, ...prev]);
  };

  // --- View Rendering Logic ---
  const renderContent = () => {
    switch (currentView) {
      case 'fleet':
        return (
          <div className="max-w-6xl mx-auto space-y-6">
            <div className="flex items-end justify-between">
              <div>
                <h1 className="text-2xl font-bold text-slate-900">Gestão de Frota</h1>
                <p className="mt-1 text-sm text-slate-500">
                  Gerencie os veículos disponíveis para verificação e operações.
                </p>
              </div>
            </div>
            <FleetManager 
              vehicles={vehicles}
              onAddVehicle={handleAddVehicle}
              onUpdateVehicle={handleUpdateVehicle}
              onDeleteVehicle={handleDeleteVehicle}
            />
          </div>
        );

      case 'validation':
        return (
          <div className="max-w-6xl mx-auto space-y-6">
            {/* Page Title & Status */}
            <div className="flex items-end justify-between">
              <div>
                <h1 className="text-2xl font-bold text-slate-900">Verificação de Odômetro</h1>
                <p className="mt-1 text-sm text-slate-500">
                  Valide a quilometragem do veículo comparando a foto do painel com a entrada manual.
                </p>
              </div>
              <div className="hidden sm:flex items-center gap-2">
                <span className="inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium bg-green-100 text-green-800 border border-green-200">
                  <span className="w-1.5 h-1.5 bg-green-500 rounded-full mr-1.5 animate-pulse"></span>
                  Sistema Online
                </span>
              </div>
            </div>

            <ValidationCard 
              vehicles={vehicles} 
              onValidationComplete={handleValidationComplete}
            />

            {/* Recent History */}
            <div className="mt-8">
              <h2 className="text-lg font-medium text-slate-900 mb-4">Histórico Recente</h2>
              <div className="bg-white shadow-sm rounded-lg border border-slate-200 overflow-hidden">
                {validationHistory.length === 0 ? (
                  <div className="p-8 text-center text-slate-500">
                    <FileText className="mx-auto h-12 w-12 text-slate-300 mb-3" />
                    <p>Nenhuma verificação realizada nesta sessão.</p>
                  </div>
                ) : (
                  <ul role="list" className="divide-y divide-slate-200">
                    {validationHistory.map((item) => {
                      const vehicle = vehicles.find(v => v.id === item.vehicleId);
                      return (
                        <li key={item.id} className="p-4 hover:bg-slate-50 transition-colors cursor-pointer">
                          <div className="flex items-center space-x-4">
                            <div className="flex-shrink-0">
                              <div className="h-10 w-10 rounded-lg bg-green-100 flex items-center justify-center text-green-600">
                                <CheckCircle2 size={20} />
                              </div>
                            </div>
                            <div className="flex-1 min-w-0">
                              <p className="text-sm font-medium text-slate-900 truncate">
                                {vehicle ? `${vehicle.name} - ${vehicle.plate}` : 'Veículo Desconhecido'}
                              </p>
                              <p className="text-sm text-slate-500 truncate">
                                Leitura: {item.manualMileage.toLocaleString('pt-BR')} km • Validado em: {new Date(item.imageDate).toLocaleString('pt-BR')}
                              </p>
                            </div>
                            <div className="flex flex-col items-end gap-1">
                              <span className="inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium bg-green-100 text-green-800">
                                Sucesso
                              </span>
                              <span className="text-xs text-slate-400">
                                IA: {(item.confidence * 100).toFixed(0)}%
                              </span>
                            </div>
                          </div>
                        </li>
                      );
                    })}
                  </ul>
                )}
              </div>
            </div>
          </div>
        );

      case 'fiscal-notes':
        return <FiscalNoteValidator />;

      default:
        return (
          <div className="flex flex-col items-center justify-center h-full text-slate-500">
            <div className="text-center">
              <h2 className="text-xl font-semibold text-slate-700">Em Desenvolvimento</h2>
              <p className="mt-2">A página "{currentView}" estará disponível em breve.</p>
              <button 
                onClick={() => setCurrentView('validation')}
                className="mt-4 text-primary hover:underline"
              >
                Voltar para Verificações
              </button>
            </div>
          </div>
        );
    }
  };

  return (
    <div className="flex h-screen bg-background-light">
      <Sidebar currentView={currentView} onNavigate={setCurrentView} />

      <main className="flex-1 flex flex-col min-w-0 overflow-hidden">
        <Header />

        <div className="flex-1 overflow-auto p-6 lg:p-8">
          {renderContent()}
        </div>
      </main>
    </div>
  );
}

